import{_ as t,o as n,c as i,ag as l}from"./chunks/framework.DTiDeF2Q.js";const f=JSON.parse('{"title":"Chmod Aliase | Dotfiles (DE)","titleTemplate":":title","description":"Vereinfachen Sie die Verwaltung von Datei- und Verzeichnisberechtigungen mit chmod-Aliase. Schnelle Verknüpfungen für gängige Berechtigungsmuster wie 755, 644 und mehr.","frontmatter":{"title":"Chmod Aliase | Dotfiles","description":"Vereinfachen Sie die Verwaltung von Datei- und Verzeichnisberechtigungen mit chmod-Aliase. Schnelle Verknüpfungen für gängige Berechtigungsmuster wie 755, 644 und mehr.","lang":"de-DE","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Chmod Aliase preview","canonical":"/de/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Chmod Aliase","pageType":"docs","schemaType":"WebPage","metaTitle":"Chmod Aliase - Dotfiles (DE)","permalink":"/de/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"chmod aliase, dateiberechtigungen, shell verknüpfungen, dotfiles, unix berechtigungen"},{"name":"twitter:card","content":"summary"},{"name":"twitter:description","content":"Vereinfachen Sie die Verwaltung von Datei- und Verzeichnisberechtigungen mit chmod-Aliase."},{"name":"twitter:title","content":"Chmod Aliase - Dotfiles"},{"name":"og:title","content":"Chmod Aliase - Dotfiles"},{"name":"og:description","content":"Vereinfachen Sie die Verwaltung von Datei- und Verzeichnisberechtigungen mit chmod-Aliase."},{"name":"og:image:alt","content":"Dotfiles - Simply designed to fit your shell life"},{"name":"og:locale","content":"de_DE"}]},"headers":[],"relativePath":"de/aliases/chmod/index.md","filePath":"de/aliases/chmod/index.md","lastUpdated":1773010926000}'),d={name:"de/aliases/chmod/index.md"};function a(r,e,s,g,c,o){return n(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="chmod-aliase" tabindex="-1">Chmod Aliase <a class="header-anchor" href="#chmod-aliase" aria-label="Permalink to &quot;Chmod Aliase&quot;">​</a></h1><p>Verknüpfungen zur Verwaltung von Datei- und Verzeichnisberechtigungen.</p><h2 id="ubersicht" tabindex="-1">Übersicht <a class="header-anchor" href="#ubersicht" aria-label="Permalink to &quot;Übersicht&quot;">​</a></h2><p>Diese Aliase sind in <code>chmod.aliases.sh</code> definiert und werden automatisch von Chezmoi geladen.</p><h2 id="referenz" tabindex="-1">Referenz <a class="header-anchor" href="#referenz" aria-label="Permalink to &quot;Referenz&quot;">​</a></h2><h3 id="gangige-berechtigungsaliase" tabindex="-1">Gängige Berechtigungsaliase <a class="header-anchor" href="#gangige-berechtigungsaliase" aria-label="Permalink to &quot;Gängige Berechtigungsaliase&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Berechtigungen</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_000</code></td><td style="text-align:left;"><code>----------</code></td><td style="text-align:left;">Keine Berechtigungen für niemanden</td></tr><tr><td style="text-align:left;"><code>chmod_400</code></td><td style="text-align:left;"><code>r--------</code></td><td style="text-align:left;">Nur Lesen für den Eigentümer</td></tr><tr><td style="text-align:left;"><code>chmod_444</code></td><td style="text-align:left;"><code>r--r--r--</code></td><td style="text-align:left;">Nur Lesen für alle</td></tr><tr><td style="text-align:left;"><code>chmod_600</code></td><td style="text-align:left;"><code>rw-------</code></td><td style="text-align:left;">Lesen/Schreiben für den Eigentümer</td></tr><tr><td style="text-align:left;"><code>chmod_644</code></td><td style="text-align:left;"><code>rw-r--r--</code></td><td style="text-align:left;">Lesen/Schreiben für Eigentümer, nur Lesen für andere</td></tr><tr><td style="text-align:left;"><code>chmod_666</code></td><td style="text-align:left;"><code>rw-rw-rw-</code></td><td style="text-align:left;">Lesen/Schreiben für alle</td></tr><tr><td style="text-align:left;"><code>chmod_755</code></td><td style="text-align:left;"><code>rwxr-xr-x</code></td><td style="text-align:left;">Voll für Eigentümer, Lesen/Ausführen für andere</td></tr><tr><td style="text-align:left;"><code>chmod_764</code></td><td style="text-align:left;"><code>rwxrw-r--</code></td><td style="text-align:left;">Voll für Eigentümer, Lesen/Schreiben für Gruppe</td></tr><tr><td style="text-align:left;"><code>chmod_777</code></td><td style="text-align:left;"><code>rwxrwxrwx</code></td><td style="text-align:left;">Volle Berechtigungen für alle</td></tr></tbody></table><h3 id="eigentumer-berechtigungsaliase" tabindex="-1">Eigentümer-Berechtigungsaliase <a class="header-anchor" href="#eigentumer-berechtigungsaliase" aria-label="Permalink to &quot;Eigentümer-Berechtigungsaliase&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_u+x</code></td><td style="text-align:left;">Ausführberechtigung für Eigentümer hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_u-x</code></td><td style="text-align:left;">Ausführberechtigung für Eigentümer entfernen</td></tr><tr><td style="text-align:left;"><code>chmod_u+w</code></td><td style="text-align:left;">Schreibberechtigung für Eigentümer hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_u-w</code></td><td style="text-align:left;">Schreibberechtigung für Eigentümer entfernen</td></tr><tr><td style="text-align:left;"><code>chmod_u+r</code></td><td style="text-align:left;">Leseberechtigung für Eigentümer hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_u-r</code></td><td style="text-align:left;">Leseberechtigung für Eigentümer entfernen</td></tr></tbody></table><h3 id="gruppen-berechtigungsaliase" tabindex="-1">Gruppen-Berechtigungsaliase <a class="header-anchor" href="#gruppen-berechtigungsaliase" aria-label="Permalink to &quot;Gruppen-Berechtigungsaliase&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_g+x</code></td><td style="text-align:left;">Ausführberechtigung für Gruppe hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_g-x</code></td><td style="text-align:left;">Ausführberechtigung für Gruppe entfernen</td></tr><tr><td style="text-align:left;"><code>chmod_g+w</code></td><td style="text-align:left;">Schreibberechtigung für Gruppe hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_g-w</code></td><td style="text-align:left;">Schreibberechtigung für Gruppe entfernen</td></tr><tr><td style="text-align:left;"><code>chmod_g+r</code></td><td style="text-align:left;">Leseberechtigung für Gruppe hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_g-r</code></td><td style="text-align:left;">Leseberechtigung für Gruppe entfernen</td></tr></tbody></table><h3 id="andere-berechtigungsaliase" tabindex="-1">Andere-Berechtigungsaliase <a class="header-anchor" href="#andere-berechtigungsaliase" aria-label="Permalink to &quot;Andere-Berechtigungsaliase&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_o+x</code></td><td style="text-align:left;">Ausführberechtigung für andere hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_o-x</code></td><td style="text-align:left;">Ausführberechtigung für andere entfernen</td></tr><tr><td style="text-align:left;"><code>chmod_o+w</code></td><td style="text-align:left;">Schreibberechtigung für andere hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_o-w</code></td><td style="text-align:left;">Schreibberechtigung für andere entfernen</td></tr><tr><td style="text-align:left;"><code>chmod_o+r</code></td><td style="text-align:left;">Leseberechtigung für andere hinzufügen</td></tr><tr><td style="text-align:left;"><code>chmod_o-r</code></td><td style="text-align:left;">Leseberechtigung für andere entfernen</td></tr></tbody></table><h3 id="dateityp-aliase" tabindex="-1">Dateityp-Aliase <a class="header-anchor" href="#dateityp-aliase" aria-label="Permalink to &quot;Dateityp-Aliase&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">Alias</th><th style="text-align:left;">Beschreibung</th></tr></thead><tbody><tr><td style="text-align:left;"><code>chmod_755d</code></td><td style="text-align:left;">Berechtigungen aller Verzeichnisse auf <code>rwxr-xr-x</code> setzen</td></tr><tr><td style="text-align:left;"><code>chmod_644f</code></td><td style="text-align:left;">Berechtigungen aller Dateien auf <code>rw-r--r--</code> setzen</td></tr></tbody></table><h3 id="rekursive-berechtigungsfunktion" tabindex="-1">Rekursive Berechtigungsfunktion <a class="header-anchor" href="#rekursive-berechtigungsfunktion" aria-label="Permalink to &quot;Rekursive Berechtigungsfunktion&quot;">​</a></h3><p>Die <code>change_permission</code>-Funktion wendet Berechtigungen rekursiv mit einer Bestätigungsaufforderung an:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',18)])])}const u=t(d,[["render",a]]);export{f as __pageData,u as default};
